{

    ios_base::sync_with_stdio(0),cin.tie(0),cout.tie(0);

    ll n,k;

    cin>>n>>k;

    for(int i=1; i<=n; i++)

    {

        ll v;

        cin>>v;

        Edge[i].push_back(v);

    }

    mark[1]=1;

    dfs(1);

    ll len=vec.size();

    if(k<len)

    {

        cout<<vec[k]<<endl;

        return 0;

    }

    ll idx=Edge[vec[len-1]][0];

    memset(mark,0,sizeof(mark));

    vec.clear();

    k-=(len-1);

    mark[idx]=1;

    dfs(idx);

    len=vec.size();

    idx=k%len;

    idx--;

    if(idx==-1)

        idx=len-1;

    cout<<vec[idx]<<endl;





    return 0;

}

